import{_ as t,o,c as u,ag as q}from"./chunks/framework.D7Ve6Z7O.js";const c=JSON.parse('{"title":"第五章","description":"","frontmatter":{},"headers":[],"relativePath":"安乐回响-AI/5.md","filePath":"安乐回响-AI/5.md","lastUpdated":1776953967000}'),r={name:"安乐回响-AI/5.md"};function a(e,p,_,s,h,n){return o(),u("div",null,[...p[0]||(p[0]=[q('<h1 id="第五章" tabindex="-1">第五章 <a class="header-anchor" href="#第五章" aria-label="Permalink to &quot;第五章&quot;">​</a></h1><p>苏寒又一次来到集会。</p><p>这次地点换成了一栋郊区的大别墅。</p><p>门口排着长队。每个人手里都拿着一个数字人格抽取设备。</p><p>入口处摆着一张桌子，工作人员正在逐个检查。</p><p>&quot;设备打开。&quot;</p><p>&quot;确认数字人格录入。&quot;</p><p>一道蓝光扫过设备。</p><p>&quot;可以进。&quot;</p><hr><p>苏寒低着头，把设备递了过去。</p><p>那是他从男人手里拿到的那台。</p><p>蓝光闪了一下。</p><p>&quot;通过。&quot;</p><p>他松了口气，走进别墅。</p><hr><p>大厅里已经聚集了不少人。</p><p>苏寒照例找了个偏僻角落坐下。</p><p>他原本以为今天还是普通集会。</p><p>但很快，人群忽然安静下来。</p><p>一个男人走上了前台。</p><p>苏寒愣了一下。</p><p>——方执。</p><p>这次，幕后老板居然亲自来了。</p><hr><p>方执的声音很平静。</p><p>&quot;各位今天来到这里，是为了见证一个新的阶段。&quot;</p><p>&quot;数字人格不应该只存在于服务器里。&quot;</p><p>&quot;今天，我们允许生者进入极乐世界。&quot;</p><p>人群瞬间骚动起来。</p><p>有人甚至站了起来。</p><p>方执继续说道：&quot;你们可以亲自进去。&quot;</p><p>&quot;见见你们想见的人。&quot;</p><hr><p>很快，工作人员开始分发设备。</p><p>一台VR头盔被递到苏寒手里。</p><p>他迟疑了一下。</p><p>但事到如今，也只能继续赌下去。</p><p>更何况——他也确实有点好奇。</p><p>这个所谓的数字世界，到底是什么样。</p><hr><p>黑暗。</p><p>随后，一阵柔和的光亮起来。</p><p>温暖的阳光落在脸上。至少他的感官是这么认为的。</p><p>苏寒睁开眼。</p><p>自己站在一片草地上。</p><p>远处是树。还有一条小路。像某种被精心设计过的公园。</p><p>周围到处都是人。</p><p>但气氛有些奇怪。</p><p>有人紧紧抱着面前的人。有人握着对方的手。还有人只是站着对视。</p><p>他们的共同点只有一个。</p><p>——全都在哭。</p><hr><p>苏寒还没完全反应过来。</p><p>忽然，一道白光在他面前闪过。</p><p>一个女人出现在他面前。</p><p>她看起来有些困惑。</p><p>&quot;你是谁？&quot;</p><p>她皱着眉。</p><p>&quot;刚刚系统告诉我……我要见我老公？&quot;</p><p>苏寒愣了一下。</p><p>糟了。</p><p>他挤出一个勉强的笑。</p><p>&quot;你先别说话。&quot;</p><p>&quot;我是你丈夫的朋友，我来是——&quot;</p><p>话还没说完。</p><p>视野里忽然弹出红色警告。</p><p>&quot;异常连接。&quot;</p><p>&quot;身份匹配失败。&quot;</p><p>下一秒。</p><p>世界瞬间黑掉。</p><hr><p>苏寒被强行摘下了VR头盔。</p><p>两个保安已经站在他身边。</p><p>&quot;起来。&quot;</p><p>他被架着拖上楼。</p><p>走廊尽头是一间没有窗户的小房间。</p><p>门&quot;砰&quot;地关上。</p><hr><p>几分钟后。</p><p>门再次打开。</p><p>走进来的是一个女人。</p><p>苏寒认出来了。</p><p>唐秘书。上次集会的主持人。</p><hr><p>苏寒决定再赌一把。</p><p>&quot;我是安乐舱公司的技术员，苏寒，工号XXXX。&quot;</p><p>&quot;我有事情要见方执。&quot;</p><p>唐秘书皱起眉。&quot;你是公司员工？&quot;</p><p>&quot;那你应该很清楚，今天发生的事情会对你的职业生涯造成什么影响。&quot;</p><p>苏寒笑了笑。&quot;我倒不太担心这个。&quot;</p><p>他看着她。</p><p>&quot;我猜，公司也不希望这件事闹大吧？&quot;</p><p>&quot;否则你们就不会把活动办得这么隐秘了。&quot;</p><p>他停顿了一下。</p><p>&quot;让我见方执。我不会把事情闹大。&quot;</p><p>&quot;否则——&quot;</p><p>他耸了耸肩。</p><p>&quot;谁知道呢。&quot;</p><hr><p>唐秘书沉默了一会。</p><p>最后叹了口气。</p><p>她转身走了出去。</p><hr><p>几分钟后，门再次打开。</p><p>&quot;来吧。&quot;她说。&quot;方总同意见你。&quot;</p><hr><p>苏寒跟着她走过长长的走廊。</p><p>走廊尽头是一扇门。</p><p>门上没有任何标识。</p><p>唐秘书推开门，示意他进去。</p><p>苏寒走进去。</p><p>门在身后关上。</p><p>房间里很暗。</p><p>只有一盏台灯亮着。</p><p>一个男人坐在桌子后面，正在把玩一个全息影像。</p><p>影像中是三个人：方执、一个小女孩，还有一个女人。</p><p>像是一家三口在野营时留下的记录，阳光透过树林洒下来，小女孩正笑着往镜头前跑。</p><p>方执抬起头，看向苏寒。</p><p>&quot;坐。&quot;</p><p>苏寒坐下。</p><p>方执缓缓放下了手中的全息影像。</p><p>&quot;你想见我，是为了什么？&quot;</p>',123)])])}const i=t(r,[["render",a]]);export{c as __pageData,i as default};
